from fastapi import APIRouter
from fastapi.responses import HTMLResponse

router = APIRouter()


@router.get("/dashboard", response_class=HTMLResponse)
async def dashboard():
    return _get_html()


def _get_html():
    # The HTML is built as a raw string to avoid escaping issues
    # It's returned as a single self-contained page
    return _HTML


